import { Component, EventEmitter, Input, Output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { MultiSelectModule } from 'primeng/multiselect';
import { PrimeMultiSelectInput } from '../../../../../adapters/multi-select.adapter';

@Component({
    selector: 'br-prime-multi-select-control',
    standalone: true,
    imports: [CommonModule, FormsModule, MultiSelectModule],
    template: `
    <div class="br-prime-multi-select-wrapper" [class]="config?.className || ''">
      <label *ngIf="config?.label" [for]="config?.id" class="br-prime-label">
        {{ config.label }}
        <span *ngIf="config.required" class="br-prime-required">*</span>
      </label>
      <div class="br-prime-control-container">
        <p-multiselect
          [options]="config?.options || []"
          [ngModel]="config?.value"
          (ngModelChange)="onValueChange($event)"
          [disabled]="config?.disabled || false"
          [id]="config?.id"
          [name]="config?.name || ''"
          optionLabel="label"
          optionValue="value"
          [required]="config?.required || false"
          placeholder="Select options"
          styleClass="w-full"
          display="chip"
        ></p-multiselect>
      </div>
    </div>
  `,
    styles: [`
    .br-prime-multi-select-wrapper {
      display: flex;
      flex-direction: column;
      gap: 0.5rem;
      margin-bottom: 1rem;
    }
    .br-prime-label {
      font-weight: 500;
      color: var(--br-text-color, #333);
      font-size: 0.875rem;
    }
    .br-prime-required {
      color: #e53e3e;
      margin-left: 0.25rem;
    }
    ::ng-deep .br-prime-control-container .p-multiselect {
      width: 100%;
    }
  `]
})
export class PrimeMultiSelectControlComponent {
    @Input() config!: PrimeMultiSelectInput;
    @Output() valueChange = new EventEmitter<any[]>();

    onValueChange(newValue: any[]) {
        this.valueChange.emit(newValue);
    }
}
