import { BrTextAreaConfig } from '../models/controls-config.model';

export interface CustomTextAreaInput {
  id?: string;
  name?: string;
  className?: string;
  label: string;
  value: string;
  placeholder: string;
  disabled: boolean;
  required: boolean;
  rows: number;
  maxLength?: number;
}

export interface MaterialTextAreaInput {
  id?: string;
  name?: string;
  className?: string;
  label: string;
  value: string;
  placeholder: string;
  disabled: boolean;
  required: boolean;
  rows: number;
  maxLength?: number;
}

export interface PrimeTextAreaInput extends CustomTextAreaInput { }

export class TextAreaAdapter {
  static toCustom(config: BrTextAreaConfig): CustomTextAreaInput {
    return {
      id: config.id || config.controlId,
      name: config.name,
      className: config.className,
      label: config.label || '',
      value: config.value || '',
      placeholder: config.placeholder || '',
      disabled: config.disabled ?? false,
      required: config.required ?? false,
      rows: config.rows ?? 4,
      maxLength: config.maxLength,
    };
  }

  static toMaterial(config: BrTextAreaConfig): MaterialTextAreaInput {
    return {
      id: config.id || config.controlId,
      name: config.name,
      className: config.className,
      label: config.label || '',
      value: config.value || '',
      placeholder: config.placeholder || '',
      disabled: config.disabled ?? false,
      required: config.required ?? false,
      rows: config.rows ?? 4,
      maxLength: config.maxLength,
    };
  }

  static toPrime(config: BrTextAreaConfig): PrimeTextAreaInput {
    return {
      id: config.id || config.controlId,
      name: config.name,
      className: config.className,
      label: config.label || '',
      value: config.value || '',
      placeholder: config.placeholder || '',
      disabled: config.disabled ?? false,
      required: config.required ?? false,
      rows: config.rows ?? 4,
      maxLength: config.maxLength,
    };
  }
}
