import { Component, EventEmitter, Input, Output, OnChanges, SimpleChanges } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { AutoCompleteModule } from 'primeng/autocomplete';
import { PrimeAutocompleteInput } from '../../../../../adapters/autocomplete.adapter';
import { BrOption } from '../../../../../models/controls-config.model';

@Component({
  selector: 'br-prime-autocomplete-control',
  standalone: true,
  imports: [CommonModule, FormsModule, AutoCompleteModule],
  template: `
    <div class="br-prime-autocomplete-wrapper" [class]="config?.className || ''">
      <label *ngIf="config?.label" [for]="config?.id" class="br-prime-label">
        {{ config.label }}
        <span *ngIf="config.required" class="br-prime-required">*</span>
      </label>
      <div class="br-prime-control-container">
        <p-autoComplete
          [ngModel]="selectedItem"
          (ngModelChange)="onModelChange($event)"
          [suggestions]="filteredOptions"
          (completeMethod)="filter($event)"
          (onClear)="onClear()"
          [disabled]="config?.disabled || false"
          [inputId]="config?.id || ''"
          [name]="config?.name || ''"
          optionLabel="label"
          [required]="config?.required || false"
          [placeholder]="config?.placeholder || ''"
          styleClass="w-full"
          [dropdown]="true"
        ></p-autoComplete>
      </div>
    </div>
  `,
  styles: [`
    .br-prime-autocomplete-wrapper {
      display: flex;
      flex-direction: column;
      gap: 0.5rem;
      margin-bottom: 1rem;
    }
    .br-prime-label {
      font-weight: 500;
      color: var(--br-text-color, #333);
      font-size: 0.875rem;
    }
    .br-prime-required {
      color: #e53e3e;
      margin-left: 0.25rem;
    }
    ::ng-deep .br-prime-control-container .p-autocomplete {
      width: 100%;
    }
    ::ng-deep .br-prime-control-container .p-autocomplete-input {
      width: 100%;
    }
  `]
})
export class PrimeAutocompleteControlComponent implements OnChanges {
  @Input() config!: PrimeAutocompleteInput;
  @Output() valueChange = new EventEmitter<any>();

  filteredOptions: BrOption[] = [];
  selectedItem: any = null;

  ngOnChanges(changes: SimpleChanges): void {
    if (changes['config'] && this.config) {
      if (this.config.value !== undefined && this.config.value !== null && this.config.value !== '') {
        const found = this.config.options?.find(o => o.value === this.config.value);
        this.selectedItem = found || { label: this.config.value, value: this.config.value };
      } else {
        this.selectedItem = null;
      }
    }
  }

  filter(event: any) {
    const query = (event.query || '').toString().toLowerCase();
    const opts = this.config?.options || [];
    this.filteredOptions = opts.filter(
      opt => {
        const lbl = (opt.label ?? opt.value ?? '').toString().toLowerCase();
        return lbl.includes(query);
      }
    );
  }

  onModelChange(event: any) {
    this.selectedItem = event;
    if (event && typeof event === 'object') {
      this.valueChange.emit(event.value !== undefined ? event.value : event);
    } else {
      this.valueChange.emit(event || '');
    }
  }

  onClear() {
    this.selectedItem = null;
    this.valueChange.emit('');
  }
}
