import { Component, Input, Output, EventEmitter, OnChanges, SimpleChanges } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { DialogModule } from 'primeng/dialog';
import { ButtonModule } from 'primeng/button';
import { InputTextModule } from 'primeng/inputtext';
import { TextareaModule } from 'primeng/textarea';
import { SelectModule } from 'primeng/select';
import { RadioButtonModule } from 'primeng/radiobutton';
import { CheckboxModule } from 'primeng/checkbox';
import { DatePickerModule } from 'primeng/datepicker';
import { MultiSelectModule } from 'primeng/multiselect';
import { AutoCompleteModule } from 'primeng/autocomplete';

import { PrimeModalInput } from '../../../adapters/modal.adapter';
import { BrModalActionEvent } from '../../../models/modal-config.model';

@Component({
    selector: 'br-prime-modal',
    standalone: true,
    imports: [
        CommonModule,
        FormsModule,
        DialogModule,
        ButtonModule,
        InputTextModule,
        TextareaModule,
        SelectModule,
        RadioButtonModule,
        CheckboxModule,
        DatePickerModule,
        MultiSelectModule,
        AutoCompleteModule
    ],
    template: `
    <p-dialog 
      [(visible)]="config.isOpen" 
      [modal]="true" 
      [closable]="config.uiConfig.showCloseButton" 
      [dismissableMask]="config.uiConfig.isDismissible"
      (onHide)="onCloseClick()"
      [header]="config.title"
      [style]="{ width: getSizeStyle() }"
      [styleClass]="config.uiConfig.className">
      
      <p *ngIf="config.subtitle" class="br-prime-modal-subtitle">{{ config.subtitle }}</p>
      <div [innerHTML]="config.content" *ngIf="config.content" class="br-prime-modal-content-html"></div>

      <div class="br-prime-modal-fields-container" *ngIf="config.fields && config.fields.length > 0">
        <div *ngFor="let field of config.fields" class="field-wrapper">
          
          <label [for]="field.id" class="field-label">{{ field.label }}<span *ngIf="field.required" class="required-mark">*</span></label>
          
          <!-- Text / Number -->
          <input *ngIf="['text', 'number'].includes(field.type)" 
            pInputText 
            [type]="field.type" 
            [id]="field.id"
            [placeholder]="field.placeholder || ''" 
            [(ngModel)]="fieldValues[field.id]"
            [name]="field.id" 
            [required]="field.required || false" 
            [disabled]="field.disabled || false"
            class="w-full" />
            
          <!-- Date -->
          <p-datepicker *ngIf="field.type === 'date'"
            [id]="field.id"
            [placeholder]="field.placeholder || ''"
            [(ngModel)]="fieldValues[field.id]"
            [name]="field.id"
            [required]="field.required || false"
            [disabled]="field.disabled || false"
            styleClass="w-full"
            dateFormat="yy-mm-dd"></p-datepicker>

          <!-- Textarea -->
          <textarea *ngIf="field.type === 'textarea'"
            pTextarea 
            [id]="field.id"
            [placeholder]="field.placeholder || ''" 
            [(ngModel)]="fieldValues[field.id]"
            [name]="field.id" 
            [required]="field.required || false"
            [disabled]="field.disabled || false"
            class="w-full"
            rows="3"></textarea>

          <!-- Select -->
          <p-select *ngIf="field.type === 'select'"
            [options]="field.options || []"
            [id]="field.id"
            [(ngModel)]="fieldValues[field.id]" 
            [name]="field.id"
            [required]="field.required || false" 
            [disabled]="field.disabled || false"
            optionLabel="label"
            optionValue="value"
            styleClass="w-full"
            [placeholder]="field.placeholder || 'Select'"
          ></p-select>

          <!-- MultiSelect -->
          <p-multiSelect *ngIf="field.type === 'multiselect'"
            [options]="field.options || []"
            [id]="field.id"
            [(ngModel)]="fieldValues[field.id]" 
            [name]="field.id"
            [required]="field.required || false" 
            [disabled]="field.disabled || false"
            optionLabel="label"
            optionValue="value"
            styleClass="w-full"
            display="chip"
            [placeholder]="field.placeholder || 'Select multiple'"
          ></p-multiSelect>

          <!-- Autocomplete -->
          <p-autoComplete *ngIf="field.type === 'autocomplete'"
            [ngModel]="getAutocompleteValue(field)"
            (ngModelChange)="onAutocompleteChange($event, field.id)"
            [suggestions]="filteredOptionsMap[field.id] || []"
            (completeMethod)="filterAutocomplete($event, field)"
            (onClear)="onAutocompleteClear(field.id)"
            [disabled]="field.disabled || false"
            [inputId]="field.id"
            [name]="field.id"
            optionLabel="label"
            [required]="field.required || false"
            [placeholder]="field.placeholder || ''"
            styleClass="w-full"
            [dropdown]="true"
          ></p-autoComplete>


          <!-- Radio -->
          <div *ngIf="field.type === 'radio'" class="radio-group-container">
            <div *ngFor="let opt of field.options" class="radio-item">
              <p-radiobutton 
                [name]="field.id" 
                [value]="opt.value" 
                [(ngModel)]="fieldValues[field.id]" 
                [inputId]="field.id + '_' + opt.value"
                [disabled]="field.disabled || false"></p-radiobutton>
              <label [for]="field.id + '_' + opt.value" class="ml-2">{{ opt.label }}</label>
            </div>
          </div>

          <!-- Checkbox -->
          <div *ngIf="field.type === 'checkbox'" class="checkbox-container flex align-items-center">
            <p-checkbox 
              [(ngModel)]="fieldValues[field.id]" 
              [binary]="true"
              [name]="field.id"
              [inputId]="field.id"
              [disabled]="field.disabled || false"></p-checkbox>
            <label [for]="field.id" class="ml-2">{{ field.placeholder || 'Yes' }}</label>
          </div>

        </div>
      </div>

      <ng-template pTemplate="footer">
        <div class="br-prime-modal-actions" *ngIf="config.actions && config.actions.length > 0">
          <p-button *ngFor="let action of config.actions" 
            [label]="action.label" 
            [severity]="getSeverity(action.type)"
            [disabled]="action.disabled || false" 
            (onClick)="onActionClick(action.id, action.label)">
          </p-button>
        </div>
      </ng-template>
    </p-dialog>
  `,
    styles: [`
    .br-prime-modal-subtitle {
      color: var(--text-color-secondary, #6c757d);
      margin-bottom: 1rem;
    }
    .br-prime-modal-content-html {
      margin-bottom: 1.5rem;
    }
    .br-prime-modal-fields-container {
      display: flex;
      flex-direction: column;
      gap: 1.5rem;
      margin-bottom: 1rem;
    }
    .field-wrapper {
      display: flex;
      flex-direction: column;
      gap: 0.5rem;
    }
    .field-label {
      font-weight: 500;
    }
    .required-mark {
      color: #e53e3e;
      margin-left: 0.25rem;
    }
    .w-full {
      width: 100%;
    }
    ::ng-deep .p-datepicker {
      width: 100%;
    }
    .radio-group-container {
      display: flex;
      gap: 1rem;
      flex-wrap: wrap;
    }
    .radio-item {
      display: flex;
      align-items: center;
    }
    .ml-2 {
      margin-left: 0.5rem;
    }
    .br-prime-modal-actions {
      display: flex;
      justify-content: flex-end;
      gap: 0.5rem;
    }
  `]
})
export class PrimeModalComponent implements OnChanges {
    @Input() config!: PrimeModalInput;
    @Output() action = new EventEmitter<BrModalActionEvent>();
    @Output() close = new EventEmitter<void>();

    fieldValues: Record<string, any> = {};
    filteredOptionsMap: Record<string, any[]> = {};

    getAutocompleteValue(field: any): any {
        const val = this.fieldValues[field.id];
        if (val !== undefined && val !== null && val !== '') {
            const found = field.options?.find((o: any) => o.value === val);
            return found || { label: val, value: val };
        }
        return null;
    }

    onAutocompleteChange(event: any, fieldId: string) {
        if (event && typeof event === 'object') {
            this.fieldValues[fieldId] = event.value !== undefined ? event.value : event;
        } else {
            this.fieldValues[fieldId] = event || '';
        }
    }

    onAutocompleteClear(fieldId: string) {
        this.fieldValues[fieldId] = null;
    }

    filterAutocomplete(event: any, field: any) {
        const query = (event.query || '').toString().toLowerCase();
        const opts = field.options || [];
        this.filteredOptionsMap[field.id] = opts.filter((opt: any) => {
            const lbl = (opt.label ?? opt.value ?? '').toString().toLowerCase();
            return lbl.includes(query);
        });
    }

    ngOnChanges(changes: SimpleChanges): void {
        if (changes['config'] && this.config?.fields) {
            this.config.fields.forEach((field: any) => {
                if (this.fieldValues[field.id] === undefined) {
                    this.fieldValues[field.id] = field.value ?? (field.type === 'checkbox' ? false : '');
                }
            });
        }
    }

    getSizeStyle(): string {
        switch (this.config?.uiConfig?.size) {
            case 'sm': return '400px';
            case 'lg': return '800px';
            case 'xl': return '1140px';
            case 'full': return '100vw';
            default: return '600px';
        }
    }

    getSeverity(type?: string): 'success' | 'info' | 'warn' | 'danger' | 'help' | 'primary' | 'secondary' | 'contrast' | null | undefined {
        if (type === 'danger') return 'danger';
        if (type === 'secondary') return 'secondary';
        return 'primary';
    }

    onActionClick(actionId: string, label: string): void {
        this.action.emit({
            actionId,
            label,
            fieldValues: { ...this.fieldValues }
        });
    }

    onCloseClick(): void {
        this.close.emit();
    }
}
