import { Component, EventEmitter, Input, Output } from '@angular/core';
import { CommonModule } from '@angular/common';
import { TableModule } from 'primeng/table';

import { GridShellInput } from '../../../adapters/grid.adapter';
import { BrGridActionEvent } from '../../../models/grid-config.model';

@Component({
    selector: 'br-prime-grid',
    standalone: true,
    imports: [CommonModule, TableModule],
    template: `
    <div class="prime-grid">
      <p-table [value]="config.data" [columns]="config.columns" [paginator]="config.pagination" [rows]="config.pageSize">
        <ng-template pTemplate="header" let-columns>
          <tr>
            <th *ngFor="let col of columns">
              {{ col.header }}
            </th>
          </tr>
        </ng-template>
        <ng-template pTemplate="body" let-rowData let-columns="columns">
          <tr>
            <td *ngFor="let col of columns">
              {{ rowData[col.field] }}
            </td>
          </tr>
        </ng-template>
      </p-table>
    </div>
  `,
    styles: [`
    .prime-grid {
      padding: 1rem;
    }
  `]
})
export class PrimeGridComponent {
    @Input() config!: GridShellInput;
    @Output() action = new EventEmitter<BrGridActionEvent>();
}
